@namespace sv_19781d26092548bf84c13b7eb591c05d.Components.Pages.Apply

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i + 1;
            var status = GetStepStatus(stepIndex);
            <li class="step-item @status" role="listitem">
                @if (status == "completed")
                {
