@namespace sv_19781d26092548bf84c13b7eb591c05d.Components.Pages.Apply
@using sv_19781d26092548bf84c13b7eb591c05d.Models

<h4 class="mb-3">Work History</h4>

@if (errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   PositionNumber="index + 1"
                   ShowRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> errors = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            if (string.IsNullOrWhiteSpace(e.Company)) errors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(e.Title)) errors.Add($"Position {i + 1}: Job title is required.");
            if (e.StartDate == null) errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

