@page "/apply"
@using sv_19781d26092548bf84c13b7eb591c05d.Components.Pages.Apply
@using sv_19781d26092548bf84c13b7eb591c05d.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="NextStep" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        SubmittedId="submittedId"
                        OnBack="PreviousStep"
                        OnEditSection="GoToStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceModel> references = new() { new(), new() };
    private string coverLetter = "";
    private int? submittedId;

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        submittedId = await ApplicationService.SubmitApplicationAsync(application);
    }
}

